module.exports = /*#__PURE__*/JSON.parse('{"translations":{"krv":{"label":"개역한글","note":"성경전서 개역한글판 (대한성서공회, 1961). 라이선스: 대한성서공회 공식 저작권 FAQ에 따라 저작재산권 보호기간 50년 경과로 저작권료 지급 없이 사용 가능 공공저작물 (개역개정판은 해당 없음). 데이터 출처: scrollmapper/bible_databases (GitHub, 2025-languages branch, sources/ko/KorRV/KorRV.json, License: Public Domain)."},"kids":{"label":"쉬운말","note":"쉬운말 번역 준비 중입니다."}},"chapters":[{"chapter":1,"title":"장로의 자격과 거짓 교사","verses":{"krv":[{"n":1,"t":"하나님의 종이요 예수 그리스도의 사도인 바울 곧 나의 사도 된 것은 하나님의 택하신 자들의 믿음과 경건함에 속한 진리의 지식과"},{"n":2,"t":"영생의 소망을 인함이라 이 영생은 거짓이 없으신 하나님이 영원한 때 전부터 약속하신 것인데"},{"n":3,"t":"자기 때에 자기의 말씀을 전도로 나타내셨으니 이 전도는 우리 구주 하나님의 명대로 내게 맡기신 것이라"},{"n":4,"t":"같은 믿음을 따라 된 나의 참 아들 디도에게 편지하노니 하나님 아버지와 그리스도 예수 우리 구주로 좇아 은혜와 평강이 네게 있을지어다"},{"n":5,"t":"내가 너를 그레데에 떨어뜨려 둔 이유는 부족한 일을 바로잡고 나의 명한 대로 각 성에 장로들을 세우게 하려 함이니"},{"n":6,"t":"책망할 것이 없고 한 아내의 남편이며 방탕하다 하는 비방이나 불순종하는 일이 없는 믿는 자녀를 둔 자라야 할지라"},{"n":7,"t":"감독은 하나님의 청지기로서 책망할 것이 없고 제 고집대로 하지 아니하며 급히 분내지 아니하며 술을 즐기지 아니하며 구타하지 아니하며 더러운 이를 탐하지 아니하며"},{"n":8,"t":"오직 나그네를 대접하며 선을 좋아하며 근신하며 의로우며 거룩하며 절제하며"},{"n":9,"t":"미쁜 말씀의 가르침을 그대로 지켜야 하리니 이는 능히 바른 교훈으로 권면하고 거스려 말하는 자들을 책망하게 하려 함이라"},{"n":10,"t":"복종치 아니하고 헛된 말을 하며 속이는 자가 많은 중 특별히 할례당 가운데 심하니"},{"n":11,"t":"저희의 입을 막을 것이라 이런 자들이 더러운 이를 취하려고 마땅치 아니한 것을 가르쳐 집들을 온통 엎드러치는도다"},{"n":12,"t":"그레데인 중에 어떤 선지자가 말하되 그레데인들은 항상 거짓말장이며 악한 짐승이며 배만 위하는 게으름장이라 하니"},{"n":13,"t":"이 증거가 참되도다 그러므로 네가 저희를 엄히 꾸짖으라 이는 저희로 하여금 믿음을 온전케 하고"},{"n":14,"t":"유대인의 허탄한 이야기와 진리를 배반하는 사람들의 명령을 좇지 않게 하려 함이라"},{"n":15,"t":"깨끗한 자들에게는 모든 것이 깨끗하나 더럽고 믿지 아니하는 자들에게는 아무 것도 깨끗한 것이 없고 오직 저희 마음과 양심이 더러운지라"},{"n":16,"t":"저희가 하나님을 시인하나 행위로는 부인하니 가증한 자요 복종치 아니하는 자요 모든 선한 일을 버리는 자니라"}],"kids":[{"n":1,"t":"하나님의 종이고 예수 그리스도의 사도가 된 나 바울이 인사해. 내가 사도가 된 것은, 하나님께서 택하신 사람들의 믿음과 그들이 경건에 따른 진리의 지식을 알게 하기 위해서야."},{"n":2,"t":"또 영생의 소망 때문이야. 이 영생은 거짓말하실 수 없는 하나님께서 영원 전부터 약속하신 것인데,"},{"n":3,"t":"정해진 때에 그분의 말씀을 전도(전파)로 드러내셨어. 이 전도는 우리 구주 하나님의 명령에 따라 내게 맡기신 거야."},{"n":4,"t":"같은 믿음을 따라 참 아들이 된 디도에게 편지를 써. 하나님 아버지와 우리 구주 그리스도 예수님께로부터 은혜와 평강이 너에게 함께하기를 빌어."},{"n":5,"t":"내가 너를 그레데(섬)에 남겨 둔 까닭은, 부족한 일을 바로잡고 내가 명령한 대로 성마다 장로들을 세우게 하려는 거야."},{"n":6,"t":"장로는 책망받을 것이 없고, 한 아내의 남편이고, 그 자녀들이 믿는 사람이고, 방탕하다는 비난을 받지 않으며 부모에게 순종하는 사람이어야 해."},{"n":7,"t":"감독은 하나님의 일을 맡은 청지기니까 책망받을 것이 없어야 해. 자기 고집대로 하지 않고, 급하게 화내지 않고, 술을 즐기지 않고, 폭력을 쓰지 않고, 더러운 돈을 탐내지 않아야 해."},{"n":8,"t":"오히려 손님을 잘 대접하고, 선한 일을 좋아하고, 신중하고, 의롭고, 거룩하고, 절제하는 사람이어야 해."},{"n":9,"t":"또 신실한 말씀의 가르침을 배운 그대로 굳게 붙들어야 해. 그래야 바른 가르침으로 권면할 수 있고, 반대하는 사람들을 책망할 수 있어."},{"n":10,"t":"순종하지 않고 헛된 말을 하며 속이는 사람이 많아. 특히 할례 받은 (유대인 출신) 사람들 가운데에 그런 사람이 많아."},{"n":11,"t":"그들의 입을 막아야 해. 그들은 더러운 돈을 얻으려고 마땅하지 않은 것을 가르쳐서, 가정 전체를 무너뜨리고 있어."},{"n":12,"t":"그레데 사람들 중에 그들 자신의 한 예언자가 이렇게 말했어. \\"그레데 사람들은 늘 거짓말쟁이이고, 악한 짐승이며, 게으른 식충이다.\\""},{"n":13,"t":"이 증언은 사실이야. 그러므로 너는 그들을 엄히 꾸짖어서 믿음이 온전해지게 하고,"},{"n":14,"t":"유대 사람의 허황된 이야기나, 진리를 저버린 사람들의 명령을 따르지 않도록 해."},{"n":15,"t":"깨끗한 사람에게는 모든 것이 깨끗하지만, 더럽고 믿지 않는 사람에게는 깨끗한 것이 하나도 없어. 오히려 그들의 마음과 양심까지 다 더러워져 있어."},{"n":16,"t":"그들은 입으로는 하나님을 안다고 하지만, 행동으로는 부인해. 그들은 가증한 사람이고, 순종하지 않는 사람이며, 모든 선한 일에 쓰임받지 못하는 사람이야."}]}},{"chapter":2,"title":"각 사람을 향한 권면","verses":{"krv":[{"n":1,"t":"오직 너는 바른 교훈에 합한 것을 말하여"},{"n":2,"t":"늙은 남자로는 절제하며 경건하며 근신하며 믿음과 사랑과 인내함에 온전케 하고"},{"n":3,"t":"늙은 여자로는 이와 같이 행실이 거룩하며 참소치 말며 많은 술의 종이 되지 말며 선한 것을 가르치는 자들이 되고"},{"n":4,"t":"저들로 젊은 여자들을 교훈하되 그 남편과 자녀를 사랑하며"},{"n":5,"t":"근신하며 순전하며 집안 일을 하며 선하며 자기 남편에게 복종하게 하라 이는 하나님의 말씀이 훼방을 받지 않게 하려 함이니라"},{"n":6,"t":"너는 이와 같이 젊은 남자들을 권면하여 근신하게 하되"},{"n":7,"t":"범사에 네 자신으로 선한 일의 본을 보여 교훈의 부패치 아니함과 경건함과"},{"n":8,"t":"책망할 것이 없는 바른 말을 하게 하라 이는 대적하는 자로 하여금 부끄러워 우리를 악하다 할 것이 없게 하려 함이라"},{"n":9,"t":"종들로는 자기 상전들에게 범사에 순종하여 기쁘게 하고 거스려 말하지 말며"},{"n":10,"t":"떼어 먹지 말고 오직 선한 충성을 다하게 하라 이는 범사에 우리 구주 하나님의 교훈을 빛나게 하려 함이라"},{"n":11,"t":"모든 사람에게 구원을 주시는 하나님의 은혜가 나타나"},{"n":12,"t":"우리를 양육하시되 경건치 않은 것과 이 세상 정욕을 다 버리고 근신함과 의로움과 경건함으로 이 세상에 살고"},{"n":13,"t":"복스러운 소망과 우리의 크신 하나님 구주 예수 그리스도의 영광이 나타나심을 기다리게 하셨으니"},{"n":14,"t":"그가 우리를 대신하여 자신을 주심은 모든 불법에서 우리를 구속하시고 우리를 깨끗하게 하사 선한 일에 열심하는 친 백성이 되게 하려 하심이니라"},{"n":15,"t":"너는 이것을 말하고 권면하며 모든 권위로 책망하여 누구에게든지 업신여김을 받지 말라"}],"kids":[]}},{"chapter":3,"title":"선한 일에 힘쓰라","verses":{"krv":[{"n":1,"t":"너는 저희로 하여금 정사와 권세잡은 자들에게 복종하며 순종하며 모든 선한 일 행하기를 예비하게 하며"},{"n":2,"t":"아무도 훼방하지 말며 다투지 말며 관용하며 범사에 온유함을 모든 사람에게 나타낼 것을 기억하게 하라"},{"n":3,"t":"우리도 전에는 어리석은 자요 순종치 아니한 자요 속은 자요 각색 정욕과 행락에 종 노릇 한 자요 악독과 투기로 지낸 자요 가증스러운 자요 피차 미워한 자이었으나"},{"n":4,"t":"우리 구주 하나님의 자비와 사람 사랑하심을 나타내실 때에"},{"n":5,"t":"우리를 구원하시되 우리의 행한 바 의로운 행위로 말미암지 아니하고 오직 그의 긍휼하심을 좇아 중생의 씻음과 성령의 새롭게 하심으로 하셨나니"},{"n":6,"t":"성령을 우리 구주 예수 그리스도로 말미암아 우리에게 풍성히 부어 주사"},{"n":7,"t":"우리로 저의 은혜를 힘입어 의롭다 하심을 얻어 영생의 소망을 따라 후사가 되게 하려 하심이라"},{"n":8,"t":"이 말이 미쁘도다 원컨대 네가 이 여러 것에 대하여 굳세게 말하라 이는 하나님을 믿는 자들로 하여금 조심하여 선한 일을 힘쓰게 하려 함이라 이것은 아름다우며 사람들에게 유익하니라"},{"n":9,"t":"그러나 어리석은 변론과 족보 이야기와 분쟁과 율법에 대한 다툼을 피하라 이것은 무익한 것이요 헛된 것이니라"},{"n":10,"t":"이단에 속한 사람을 한두 번 훈계한 후에 멀리 하라"},{"n":11,"t":"이러한 사람은 네가 아는 바와 같이 부패하여서 스스로 정죄한 자로서 죄를 짓느니라"},{"n":12,"t":"내가 아데마나 두기고를 네게 보내리니 그 때에 네가 급히 니고볼리로 내게 오라 내가 거기서 과동하기로 작정하였노라"},{"n":13,"t":"교법사 세나와 및 아볼로를 급히 먼저 보내어 저희로 궁핍함이 없게 하고"},{"n":14,"t":"또 우리 사람들도 열매 없는 자가 되지 않게 하기 위하여 필요한 것을 예비하는 좋은 일에 힘쓰기를 배우게 하라"},{"n":15,"t":"나와 함께 있는 자가 다 네게 문안하니 믿음 안에서 우리를 사랑하는 자들에게 너도 문안하라 은혜가 너희 무리에게 있을지어다"}],"kids":[]}}]}');

